## Summary

I've thoroughly explored the project's entry point and configuration files. Here are the complete contents of all relevant files:

### **src/app.ts**
```typescript
import express from "express";
import { router } from "./routes.js";

const app = express();
app.use(express.json());
app.use(router);

export { app };
```

### **src/routes.ts**
```typescript
import { Router } from "express";
import { users } from "./data.js";

const router = Router();

// GET /users - returns all users
router.get("/users", (req, res) => {
  res.json(users);
});

// GET /users/:id - returns a single user
router.get("/users/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const user = users.find((u) => u.id === id);
  if (!user) {
    res.status(404).json({ error: "User not found" });
    return;
  }
  res.json(user);
});

export { router };
```

### **src/types.ts**
```typescript
export interface User {
  id: number;
  name: string;
  email: string;
  role: "admin" | "user";
}
```

### **src/data.ts**
```typescript
